/**
 * Transfers data from one sheet to another within the same spreadsheet.
 * Handles merged cells appropriately.
 * 
 * This script can be set up as a trigger to run automatically or called manually.
 */

function transferData() {
  // Get the active spreadsheet
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  // Replace these with your actual sheet names
  const sourceSheetName = "Project_EstimateSheet";
  const targetSheetName = "Project_Proposal";

  // Get the source and target sheets
  const sourceSheet = ss.getSheetByName(sourceSheetName);
  const targetSheet = ss.getSheetByName(targetSheetName);

  // Check if both sheets exist
  if (!sourceSheet || !targetSheet) {
    Logger.log("Error: One or both sheets not found!");
    return;
  }

  // Replace these with your actual cell references
  const sourceCellReference = "M6:N6"; // Example: cell to get data from
  const targetCellReference = "D19:E19"; // Example: cell to update

  // Get value from source cell (even if it's part of a merged range)
  const sourceValue = sourceSheet.getRange(sourceCellReference).getValue();

  // Check if target cell is part of a merged range
  const targetRange = targetSheet.getRange(targetCellReference);
  const mergedRanges = targetSheet.getMergedRanges();
  let mergedRange = null;

  // Find if target cell is part of a merged range
  for (let i = 0; i < mergedRanges.length; i++) {
    if (mergedRanges[i].containsRange(targetRange)) {
      mergedRange = mergedRanges[i];
      break;
    }
  }

  // If target is part of a merged range, get the top-left cell
  if (mergedRange) {
    const topRow = mergedRange.getRow();
    const leftCol = mergedRange.getColumn();
    targetSheet.getRange(topRow, leftCol).setValue(sourceValue);
    Logger.log("Data transferred to merged range starting at row " + topRow + ", column " + leftCol);
  } else {
    // Set value in target cell (not merged)
    targetRange.setValue(sourceValue);
  }

  Logger.log("Data transferred successfully from " + sourceSheetName + "!" + sourceCellReference + 
             " to " + targetSheetName + "!" + targetCellReference);
}

