/**
 * Function that can transfer data from a specific cell to a specific target cell.
 * This version allows you to specify the source and target locations as parameters.
 */
function transferSpecificCells(sourceSheet, sourceCell, targetSheet, targetCell) {
  // Get the active spreadsheet
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  // Get the source and target sheets
  const srcSheet = ss.getSheetByName(sourceSheet);
  const tgtSheet = ss.getSheetByName(targetSheet);

  // Check if both sheets exist
  if (!srcSheet || !tgtSheet) {
    Logger.log("Error: One or both sheets not found!");
    return;
  }

  // Get value from source cell
  const sourceValue = srcSheet.getRange(sourceCell).getValue();

  // Set value in target cell
  tgtSheet.getRange(targetCell).setValue(sourceValue);

  Logger.log("Data transferred successfully from " + sourceSheet + "!" + sourceCell + 
             " to " + targetSheet + "!" + targetCell);
}

/**
