    return;
  }

  // Get the source range and check if it's part of a merged range
  const sourceRange = sourceSheet.getRange(sourceCellReference);
  const sourceMergedRanges = sourceSheet.getMergedRanges();
  let sourceMergedRange = null;

  // Find if source cell is part of a merged range
  for (let i = 0; i < sourceMergedRanges.length; i++) {
    if (sourceMergedRanges[i].containsRange(sourceRange)) {
